#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
	double a[302],maxn=-1000000001.0,minn=10000000001.0,b,c,sum=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        if(a[i]>maxn)maxn=a[i],b=i;
        if(a[i]<minn)minn=a[i],c=i;
        sum+=a[i];
    }
    double ans1=(sum-maxn-minn)/(1.0*n-2.0),ans2=0.0;
    for(int i=1;i<=n;i++)
    	if(i!=b && i!=c)ans2=max(ans2,abs(ans1-a[i]));
    printf("%.2lf %.2lf",ans1,ans2);
    return 0;
}
